sections.solution:
import Foundation

var featureEnabled = false

struct ToggleFeatureIntent {
    func perform() -> String {
        featureEnabled.toggle()
        return "Feature is now enabled: \(featureEnabled)"
    }
}

let intent = ToggleFeatureIntent()
let result = intent.perform()
print(result)

