sections.solution:
import Foundation

func handleDeepLink(_ url: String) -> String {
    let parts = url.components(separatedBy: "/")
    let taskId = parts.last ?? "unknown"
    return "Showing task \(taskId)"
}

let result = handleDeepLink("myapp://tasks/42")
print(result)
